```xml
// pages/Quiz.tsx
import React, { useState } from 'react';

// Assuming you have a question data structure and a video component
interface Question {
  id: number;
  questionText: string;
  options: string[];
  correctAnswer: number; // Index of the correct answer
}

interface QuizProps {
  questions: Question[];
}

const Quiz: React.FC<QuizProps> = ({ questions }) => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [showVideo, setShowVideo] = useState(false);

  const handleAnswerSelection = (answerIndex: number) => {
    setSelectedAnswer(answerIndex);
    setShowVideo(true); // Assuming the video should show after selection
  };

  const handleNextQuestion = () => {
    setSelectedAnswer(null); // Reset for the next question
    setShowVideo(false);
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(currentQuestionIndex + 1);
    }
  };

  const handlePreviousQuestion = () => {
    setSelectedAnswer(null); // Reset for the previous question
    setShowVideo(false);
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex(currentQuestionIndex - 1);
    }
  };

  const handlePaletteClick = (index: number) => {
      setCurrentQuestionIndex(index);
      setSelectedAnswer(null); //resetting selected answer
      setShowVideo(false); //hiding the video
  }

  const currentQuestion = questions[currentQuestionIndex];

  return (
    <div>
      {/* ... other components ... */}
      <div className="mb-4">
        {questions.map((_, index) => (
          <button
            key={index}
            className={`mr-2 px-3 py-1 rounded-md ${
              currentQuestionIndex === index ? 'bg-secondary-500 text-white' : 'bg-gray-200 text-gray-700'
            }`}
            onClick={() => handlePaletteClick(index)}
          >
            {index + 1}
          </button>
        ))}
      </div>
      {/* ... rest of the quiz interface ... */}
    </div>
  );
};

export default Quiz;
```


