```typescript
import Link from 'next/link';
import { useRouter } from 'next/router';
import { useEffect, useState } from 'react';
import { useQuery } from 'react-query';

import { useAuth } from '@/context/AuthContext';
import { fetchUserReport } from '@/services/apiService';
import { Skill, SkillLevel } from '@/types/skill';

const getColorClass = (mastery: number): string => {
  if (mastery < 50) return 'text-red-500';
  if (mastery < 70) return 'text-amber-500';
  return 'text-green-500';
};

const Reports = () => {
  const router = useRouter();
  const { user } = useAuth();
  const userId = user?.id;
  const { data: report, isLoading, error } = useQuery(
    ['userReport', userId],
    () => fetchUserReport(userId),
    {
      enabled: !!userId,
    }
  );
  const [showAdditionalTestAlert, setShowAdditionalTestAlert] = useState(false);

  useEffect(() => {
    if (report && report.skills.some((skill) => skill.mastery < 50)) {
      setShowAdditionalTestAlert(true);
    } else {
      setShowAdditionalTestAlert(false);
    }
  }, [report]);

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {JSON.stringify(error)}</div>;
  if (!report) return <div>No report available.</div>;

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <Link href="/dashboard" className="text-blue-500 hover:underline">
          &larr; Back to Dashboard
        </Link>
        <h1 className="text-2xl font-bold">Your Report</h1>
      </div>

      {showAdditionalTestAlert && (
        <div className="border-2 border-red-500 bg-gray-100 p-4 mb-4 rounded-md">
          <p className="text-red-600 font-bold text-lg mb-2">
            You have some skills that need extra practice.
          </p>
          <p>
            <Link
              href="/quiz"
              className="text-white bg-red-500 hover:bg-red-700 font-medium py-2 px-4 rounded-md inline-block"
            >
              Take Additional Test
            </Link>
          </p>
        </div>
      )}

      {report.skills.map((skill: Skill) => (
        <div key={skill.id} className="mb-4 p-4 border rounded-md">
          <h2 className="text-lg font-semibold mb-2">{skill.name}</h2>
          <p className="mb-2">
            Mastery:{' '}
            <span className={getColorClass(skill.mastery)}>{skill.mastery}%</span>
          </p>

          <p className="mb-2">Current Level: {skill.level}</p>

          {skill.mastery < 50 && (
            <div className="mt-2">
              <Link
                href="/quiz"
                className="text-white bg-red-500 hover:bg-red-700 font-medium py-2 px-4 rounded-md inline-block"
              >
                Take Additional Test
              </Link>
            </div>
          )}
        </div>
      ))}
    </div>
  );
};

export default Reports;
```

